class Solution {
    public ListNode removeZeroSumSublists(ListNode head) {
        ListNode dummy = new ListNode(0);
        dummy.next = head;
        int prefix = 0;
        Map<Integer, ListNode> map = new HashMap<>();
        map.put(0, dummy);
        while (head != null) {
            prefix += head.val;
            if (map.containsKey(prefix)) {
                ListNode node = map.get(prefix);
                ListNode tmp = node.next;
                int tmpPrefix = prefix + tmp.val;
                while (tmp != head) {
                    map.remove(tmpPrefix);
                    tmp = tmp.next;
                    tmpPrefix += tmp.val;
                }
                node.next = head.next;
            } else {
                map.put(prefix, head);
            }
            head = head.next;
        }
        return dummy.next;
    }
}
